arguments.file_text:
@using sv_930d840a521642fabfc24863d5486154.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    width: 100%;
    height: 100%;
    background: #2f3136;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid rgba(255,255,255,0.06);
}

.sidebar-header h3 {
    margin: 0;
    color: #fff;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px;
}

@using sv_930d840a521642fabfc24863d5486154.Services

<div class="message-list" @onscroll="HandleScroll" @ref="scrollContainer">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ThreadReplyCount="GetThreadReplyCount(message.Id)"
                     OnReply="OnReply"
                     OnViewThread="OnViewThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnReply { get; set; }
    [Parameter] public EventCallback<int> OnViewThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference scrollContainer;

    private int GetThreadReplyCount(int messageId) =>
        ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    private async Task HandleScroll()
    {
        // We'll use JS interop to detect scroll-to-top for pagination
        await OnLoadMore.InvokeAsync();
    }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 0.85rem;
    color: #888;
}

@using sv_930d840a521642fabfc24863d5486154.Services

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="area-header">
            <h2># @Channel.Name</h2>
            <span class="area-description">@Channel.Description</span>
        </div>

        <MessageList Messages="Messages"
                     ThreadSummaries="ThreadSummaries"
                     IsLoadingMore="IsLoadingMore"
                     OnLoadMore="OnLoadMore"
                     OnReply="OnReply"
                     OnViewThread="OnViewThread"
                     OnReact="OnReact" />

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonLabel="Send"
                      OnSubmit="OnSendMessage" />
    }
    else
    {
        <div class="no-channel">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnReply { get; set; }
    [Parameter] public EventCallback<int> OnViewThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
}

.message-area {
    height: 100%;
    display: flex;
    flex-direction: column;
    background: #fff;
    overflow: hidden;
}

.area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 1.15rem;
    color: #1a1a2e;
}

.area-description {
    font-size: 0.82rem;
    color: #777;
}

.no-channel {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 1.1rem;
}

@using sv_930d840a521642fabfc24863d5486154.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="author">@reply.Author</span>
                        <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSubmit="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

